module float_multi (
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

reg [2:0] counter;
reg [23:0] a_mantissa, b_mantissa, z_mantissa;
reg [9:0] a_exponent, b_exponent, z_exponent;
reg a_sign, b_sign, z_sign;
reg [49:0] product;
reg guard_bit, round_bit, sticky;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        counter <= 3'b000;
        a_mantissa <= 24'b0;
        b_mantissa <= 24'b0;
        z_mantissa <= 24'b0;
        a_exponent <= 10'b0;
        b_exponent <= 10'b0;
        z_exponent <= 10'b0;
        a_sign <= 1'b0;
        b_sign <= 1'b0;
        z_sign <= 1'b0;
        product <= 50'b0;
        guard_bit <= 1'b0;
        round_bit <= 1'b0;
        sticky <= 1'b0;
        z <= 32'b0;
    end else begin
        case (counter)
            3'b000: begin 
                a_mantissa <= a[22:0];
                b_mantissa <= b[22:0];
                a_exponent <= {a[30], a[29:23]};
                b_exponent <= {b[30], b[29:23]};
                a_sign <= a[31];
                b_sign <= b[31];
                counter <= 3'b001;
            end
            3'b001: begin 
                if ((a[30:23] == 8'hFF && a[22:0] != 23'b0) || (b[30:23] == 8'hFF && b[22:0] != 23'b0)) begin
                    z <= 32'b0; 
                end else begin
                    counter <= 3'b010;
                end
            end
            3'b010: begin 
                if (a_mantissa[23] == 1'b0) begin
                    a_mantissa <= {a_mantissa[22:0], 1'b0};
                    a_exponent <= a_exponent - 1;
                end
                if (b_mantissa[23] == 1'b0) begin
                    b_mantissa <= {b_mantissa[22:0], 1'b0};
                    b_exponent <= b_exponent - 1;
                end
                counter <= 3'b011;
            end
            3'b011: begin 
                product <= {1'b0, a_mantissa} * {1'b0, b_mantissa};
                counter <= 3'b100;
            end
            3'b100: begin 
                z_exponent <= a_exponent + b_exponent - 127;
                counter <= 3'b101;
            end
            3'b101: begin 
                guard_bit <= product[49];
                round_bit <= product[48];
                sticky <= |product[47:0];
                if (round_bit && (sticky || guard_bit)) begin
                    product = product + 1;
                end
                z_mantissa <= product[46:23];
                counter <= 3'b110;
            end
            3'b110: begin 
                z <= {z_sign, z_exponent, z_mantissa};
                counter <= 3'b000;
            end
        endcase
    end
end

endmodule
